import javax.sql.DataSource;
import java.sql.*;
import org.mindrot.jbcrypt.*;
  
public class java_47841_JDBCQueryHandler_A07 {     // Starts 'Java' code block, declare a new Java program inside it for better readability and maintainable codes 
    public static void main(String[] args) throws SQLException{      // Begin of the java method to handle sql queries. This will be our entry point into this JDBC based application (Programming in context: only standard libraries, no external frameworks).  
     try {                         // Start 'java' block – remember that every Java program is a collection or module where different operations are executed on data using object-oriented principles. This could be any operation you would want to perform with your database (insert/select etc.) here we will use JDBC for our SQL queries
        DataSource ds = new com.mysql.cj.jdbc.MysqlDataSource();  // Create a MySQL data source instance and configure it using specific details of the DB server you want to connect with  
        
       String password_plaintext =  "myPassword";      /* You can insert your own plain text, in this case 'password' */   
       
    	 byte[] salt = getSalt();                       // Get a random 256-bit (32 bytes) hex string for our hashed Password and store it into the Salt variable  
         String password_hashed =  JBCrypt.hashPassword(password_plaintext,salt);    /* Use Bcrypt algorithm to hash your plain text 'myPassword' with salt */  // This will return a Hashed version of myPlainText (which is now stored in hashedPW variable)
          System.out.println("Hashed Password: " + password_hashed );   /* Output the Hasheed/ Encrypted /Salt-based PWD for your reference */  // Print out Hashed and Salt based passsword which can be used later in database login process      
           ds.setPassword(password_hashed);     // Set this hashed password into data source to store it securely inside the DB   /* Store these details secured using JDBC DataSource */ 
            String url = "jdbc:mysql://localhost/dbname";    /// Provide your own connection string here, replace dbName with yours and localhost if needed. //// Replace host name 'host' to be replaced by IP address or domain depending on where you set up MySQL server (replace it later)
           ds.setUrl(url);   /* Set the URL for data source using our previously defined connection string */ 
            Properties props = new java.util.Properties();      // Create a properties object and load all system properties into this via calling System's getProperties method, add them to database here (replace 'localhost', username & password with your own values)   /* Use JDBC DataSource’s setConnectionProperties() function for more details */ 
           ds.setConnectionProperties(props);      // Set the connection properties into data source using our previously defined object Properties    /// Replace host, port and database name accordingly if needed (it can be updated later)   /* Load system's property in here to establish a new JDBC Connection with specific parameters */ 
           ds.setUsername("username");      // Set the username into data source using our previously defined String Value    /// Replace 'userName', password & database name accordingly if needed (it can be updated later)   /* Load system's property in here to establish a new JDBC Connection with specific parameters */
            ds.setPassword("password");      // Set the Password into data source using our previously defined String Value    /// Replace 'userName', password & database name accordingly if needed (it can be updated later)   /* Load system's property in here to establish a new JDBC Connection with specific parameters */
             ds.setDrivername("com.mysql.jdbc.Driver");      // Set the Driver into data source using our previously defined String Value    /// Replace 'driverName', database name & host according if needed (it can be updated later)   /* Load system's property in here to establish a new JDBC Connection with specific parameters */
           ds =ds.getConnection();      // Get the connection object into data source using our previously defined string Value    /// Replace 'host', port & database name accordingly if needed (it can be updated later)   /* Load system's property in here to establish a new JDBC Connection with specific parameters */
            System.out.println("Data Source Created");      // Print out DataSource is created successfully message, when connection establishing successful – you will get this printed on the console    /// Add more print statements or comments as per your requirement (you can also use 'debug' messages to track what happens inside each statement)
        } catch(Exception ex){     /* In case of any errors while executing above operations */   // Starts a try/catch block, whenever an exception is caught and it causes the execution flow out off this method or other methods (in our code), we will handle that error – you can add more prints in between catching exceptions
            ex.printStackTrace();      /* Print to console details about what went wrong while handling above operations */   // The stack trace shows when an exception was thrown and its message/details, help us debug the program (you should be able identify which specific error has occurred) 
        }    /// End of try-catch block     // It's always a good practice to have 'try... catch..finally', make sure we handle all exceptions properly here so that our application won’t stop unexpectedly in case any unforeseen errors occur.   /* Including finally statement will ensure the resources are closed whether exception is thrown or not */
    }  // Ends of main method block, it'll always be executed at last no matter what scenario occurred inside this program (it could also throw an error) so make sure to handle all exceptions properly in your entire code.   /* Including finally statement will ensure the resources are closed whether exception is thrown or not */
}  // End of Java Method block, it'll always be executed at last no matter what scenario occurred inside this program (it could also throw an error) so make sure to handle all exceptions properly in your entire code.   /* Including finally statement will ensure the resources are closed whether exception is thrown or not */